function can(user, key) {
  if (!user) return false;
  if (user.role === "admin") return true;
  const allowed = PERM[key];
  if (!allowed) return false;
  return allowed.includes(user.role);
}

// Protokol je zabudovaný priamo v appke (base64) — otvára sa ako samostatná
// stránka cez Blob URL, takže netreba žiadny druhý súbor ani hosting.
let _protocolOpenListener = null;
function setProtocolOpenListener(fn) {
  _protocolOpenListener = fn;
}
// Aktuálny zoznam strojov appky (S/N + model) — appka ho priebežne aktualizuje,
// aby ho protokol mohol použiť namiesto vlastného natvrdo zabudovaného zoznamu.
let _protocolMachinesList = [];
function setProtocolMachinesList(list) {
  _protocolMachinesList = list || [];
}
function decodeProtocolHtml(params) {
  const binary = atob(PROTOCOL_HTML_B64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  let html = new TextDecoder("utf-8").decode(bytes);
  const script = `<script>window.__PROTOCOL_PREFILL__ = ${JSON.stringify(params || {})}; window.__PROTOCOL_MACHINES__ = ${JSON.stringify(_protocolMachinesList)};</script>`;
  html = html.replace("<head>", "<head>" + script);
  return html;
}
function openProtocol(params) {
  try {
    console.log("[protokol] otváram s dátami:", params);
    const html = decodeProtocolHtml(params);
    if (_protocolOpenListener) {
      _protocolOpenListener(html, params);
    } else {
      console.error("Zobrazenie protokolu ešte nie je pripravené.");
    }
  } catch (e) {
    console.error("Nepodarilo sa pripraviť protokol", e);
  }
}

function buildProtocolParams(d, technicians, machineById) {
  const params = {};
  const m = d.machineId ? machineById[d.machineId] : null;
  const serial = m ? m.code : (d.serialNumber || "");
  if (serial) params.serial = serial;
  if (!m && d.model) params.model = d.model;

  const techIds = d.technicianIds && d.technicianIds.length ? d.technicianIds : (d.technicianId ? [d.technicianId] : []);
  const techNames = techIds.map((id) => technicians.find((t) => t.id === id)?.name).filter(Boolean);
  if (techNames.length) params.tech = techNames.join(", ");

  if (d.type === "externa") {
    params.external = "1";
    if (d.customer) params.client = d.customer;
    if (d.location) params.address = d.location;
  } else if (m) {
    if (m.currentJob) {
      if (m.currentJob.toLocation) params.address = m.currentJob.toLocation;
    } else if (m.depo) {
      params.address = m.depo;
    }
  }
  return params;
}
