const toLocalISO = (d) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
const todayISO = () => toLocalISO(new Date());
const addDaysISO = (iso, days) => {
  const d = new Date(iso + "T00:00:00");
  const shifted = new Date(d.getTime() + days * 86400000);
  return toLocalISO(shifted);
};
function weekRangeFor(iso) {
  const d = new Date(iso + "T00:00:00");
  const dow = d.getDay();
  const mondayOffset = dow === 0 ? -6 : 1 - dow;
  const weekStart = addDaysISO(iso, mondayOffset);
  const weekEnd = addDaysISO(weekStart, 6);
  return { weekStart, weekEnd };
}
const fmtDate = (iso) => {
  if (!iso) return "—";
  const [y, m, d] = iso.split("-");
  return `${d}.${m}.${y}`;
};
const daysBetween = (a, b) => {
  const d1 = new Date(a + "T00:00:00");
  const d2 = new Date(b + "T00:00:00");
  return Math.round((d2 - d1) / 86400000);
};
const uid = () => Math.random().toString(36).slice(2, 10) + Date.now().toString(36).slice(-4);

function effectiveStatus(job, today) {
  if (!job) return null;
  if (job.status === "completed") return "completed";
  if (today < job.startDate) return "planned";
  if (today > job.endDate) return "overdue";
  return "active";
}

function currentJobFor(jobs, machineId, today) {
  const candidates = jobs
    .filter((j) => j.machineId === machineId && j.status !== "completed")
    .filter((j) => j.startDate <= today)
    .sort((a, b) => (a.startDate < b.startDate ? 1 : -1));
  return candidates[0] || null;
}
function nextJobFor(jobs, machineId, today) {
  const candidates = jobs
    .filter((j) => j.machineId === machineId && j.status !== "completed")
    .filter((j) => j.startDate > today)
    .sort((a, b) => (a.startDate > b.startDate ? 1 : -1));
  return candidates[0] || null;
}

/* ---------------------------------------------------------
   Storage helpers — backed by Supabase (tabuľka app_data: key, value, updated_at)
--------------------------------------------------------- */
const supabase = createClient(
  import.meta.env.VITE_SUPABASE_URL,
  import.meta.env.VITE_SUPABASE_ANON_KEY
);

async function loadKey(key, fallback) {
  try {
    const { data, error } = await supabase.from("app_data").select("value").eq("key", key).maybeSingle();
    if (error || !data) return fallback;
    return data.value ?? fallback;
  } catch (e) {
    console.error("loadKey failed", key, e);
    return fallback;
  }
}
const _saveQueues = {};
const _lastValues = {};
let _saveStatusListener = null;
function setSaveStatusListener(fn) {
  _saveStatusListener = fn;
}
function retrySave(key) {
  if (key in _lastValues) saveKey(key, _lastValues[key]);
}
const sleep = (ms) => new Promise((res) => setTimeout(res, ms));

async function writeWithRetry(key, value, attempt = 1) {
  try {
    const { error } = await supabase.from("app_data").upsert({ key, value, updated_at: new Date().toISOString() });
    if (error) throw error;
    return true;
  } catch (e) {
    if (attempt < 4) {
      await sleep(attempt * 800);
      return writeWithRetry(key, value, attempt + 1);
    }
    console.error("Storage save failed after retries", key, e);
    return false;
  }
}

function saveKey(key, value) {
  _lastValues[key] = value;
  // Last-write-wins by default, so without sequencing an older save could
  // finish after a newer one and clobber it. Chain writes per key so they
  // always land in the order they were called.
  const prev = _saveQueues[key] || Promise.resolve();
  const next = prev.then(async () => {
    _saveStatusListener?.("pending", key);
    const ok = await writeWithRetry(key, value);
    _saveStatusListener?.(ok ? "ok" : "error", key);
  });
  _saveQueues[key] = next;
  return next;
}


/* ---------------------------------------------------------
   Searchable select
--------------------------------------------------------- */
function SearchSelect({ options, value, onChange, placeholder, disabled }) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const selected = options.find((o) => o.value === value);
  const filtered = (query
    ? options.filter((o) => o.label.toLowerCase().includes(query.toLowerCase()))
    : options
  ).slice(0, 60);

  return (
    <div style={{ position: "relative" }}>
      <input
        disabled={disabled}
        value={open ? query : selected ? selected.label : ""}
        onFocus={() => {
          setOpen(true);
          setQuery("");
        }}
        onChange={(e) => setQuery(e.target.value)}
        placeholder={placeholder}
        style={{ width: "100%" }}
      />
      {open && (
        <>
          <div
            onClick={() => setOpen(false)}
            style={{ position: "fixed", inset: 0, zIndex: 40 }}
          />
          <div
            className="panel"
            style={{
              position: "absolute",
              top: "calc(100% + 4px)",
              left: 0,
              right: 0,
              maxHeight: 220,
              overflowY: "auto",
              zIndex: 50,
              padding: 4,
            }}
          >
            {filtered.length === 0 && (
              <div style={{ padding: 8, color: "var(--text-dim)", fontSize: 13 }}>
                Žiadne výsledky
              </div>
            )}
            {filtered.map((o) => (
              <div
                key={o.value}
                onClick={() => {
                  onChange(o.value);
                  setOpen(false);
                }}
                style={{
                  padding: "6px 8px",
                  borderRadius: 4,
                  cursor: "pointer",
                  fontSize: 13,
                }}
                onMouseEnter={(e) => (e.currentTarget.style.background = "rgba(255,138,30,.12)")}
                onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}
              >
                {o.label}
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

/* ---------------------------------------------------------
   Status badge
--------------------------------------------------------- */
function StatusBadge({ status }) {
  const map = {
    active: { cls: "badge-info", label: "Na zákazke" },
    planned: { cls: "badge-warn", label: "Naplánovaná" },
    overdue: { cls: "badge-danger", label: "Po termíne" },
    completed: { cls: "badge-ok", label: "Dokončená" },
    free: { cls: "badge-ok", label: "Voľný" },
  };
  const m = map[status] || { cls: "badge-ok", label: status };
  return <span className={`badge ${m.cls}`}>{m.label}</span>;
}

/* ---------------------------------------------------------
   Modal shell
--------------------------------------------------------- */
function Modal({ title, onClose, children, wide }) {
  return (
    <div
      className="modal-overlay"
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,.55)",
        zIndex: 100,
        display: "flex",
        alignItems: "flex-start",
        justifyContent: "center",
        padding: "40px 16px",
        overflowY: "auto",
      }}
      onClick={onClose}
    >
      <div
        className="panel modal-panel"
        onClick={(e) => e.stopPropagation()}
        style={{ width: wide ? 640 : 460, maxWidth: "100%", padding: 20 }}
      >
        <div className="modal-header" style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <h3 className="label-font" style={{ fontSize: 18, margin: 0, color: "var(--accent)" }}>
            {title}
          </h3>
          <button className="btn btn-ghost" onClick={onClose}>
            Zavrieť
          </button>
        </div>
        {children}
      </div>
    </div>
  );
}

/* ---------------------------------------------------------
   Two-step delete confirmation (native confirm() is unreliable
   in sandboxed environments, so this is a real in-app modal)
--------------------------------------------------------- */
function ConfirmDeleteModal({ label, onClose, onConfirm }) {
  const [step, setStep] = useState(1);
  return (
    <Modal title={step === 1 ? "Naozaj vymazať?" : "Potvrďte vymazanie"} onClose={onClose}>
      {step === 1 ? (
        <>
          <div style={{ fontSize: 14, marginBottom: 18 }}>Naozaj chcete vymazať {label}?</div>
          <div style={{ display: "flex", gap: 8 }}>
            <button className="btn btn-ghost" onClick={onClose}>Zrušiť</button>
            <button className="btn" style={{ background: "var(--danger)", color: "#fff" }} onClick={() => setStep(2)}>
              Áno, pokračovať
            </button>
          </div>
        </>
      ) : (
        <>
          <div style={{ fontSize: 14, marginBottom: 18, color: "var(--danger)", fontWeight: 600 }}>
            Potvrďte vymazanie: {label}. Tento krok sa nedá vrátiť späť.
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button className="btn btn-ghost" onClick={onClose}>Zrušiť</button>
            <button
              className="btn"
              style={{ background: "var(--danger)", color: "#fff" }}
              onClick={() => {
                onConfirm();
                onClose();
              }}
            >
              Vymazať natrvalo
            </button>
          </div>
        </>
      )}
    </Modal>
  );
}

