function DamagesView({ damages, technicians, machineById, user, onAssign, onDelete, onResolve, onComplete, onProtocol }) {
  const [activeFilters, setActiveFilters] = useState(() => new Set(["new", "assigned"]));
  const [depoFilter, setDepoFilter] = useState(null);
  const [search, setSearch] = useState("");
  const depoOptions = DEPO_OPTIONS;
  const filtered = damages.filter((d) => d.type !== "revizia" && d.type !== "uradnaSkuska" && d.type !== "externa");
  let statusFiltered = filtered.filter((d) => {
    const status = d.resolved ? "resolved" : d.technicianId ? "assigned" : "new";
    return activeFilters.has(status);
  });
  if (depoFilter) {
    statusFiltered = statusFiltered.filter((d) => (machineById[d.machineId]?.depo || "").toLowerCase() === depoFilter.toLowerCase());
  }
  if (search.trim()) {
    const q = search.toLowerCase();
    statusFiltered = statusFiltered.filter((d) => {
      const m = machineById[d.machineId];
      return (
        (d.code || "").toLowerCase().includes(q) ||
        (d.model || "").toLowerCase().includes(q) ||
        (m?.depo || "").toLowerCase().includes(q) ||
        (m?.currentJob?.customer || m?.currentJob?.toLocation || "").toLowerCase().includes(q) ||
        (d.popis || "").toLowerCase().includes(q)
      );
    });
  }
  const sorted = [...statusFiltered].sort((a, b) => (a.dateReported < b.dateReported ? 1 : -1));
  const technicianById = useMemo(() => Object.fromEntries(technicians.map((t) => [t.id, t])), [technicians]);

  function locationLabel(d) {
    const m = machineById[d.machineId];
    if (!m) return null;
    return m.currentJob ? `Zákazka: ${m.currentJob.customer || m.currentJob.toLocation}` : `Depo: ${m.depo || "—"}`;
  }

  const filterButtons = [
    { id: "new", label: "Nahlásené" },
    { id: "assigned", label: "Pridelené" },
    { id: "resolved", label: "Vyriešené" },
  ];

  function toggleFilter(id) {
    setActiveFilters((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  return (
    <div>
      <div style={{ marginBottom: 10 }}>
        <input
          placeholder="Hľadať sériové číslo, model, depo, zákazku, popis…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={{ minWidth: 260 }}
        />
      </div>
      <div style={{ display: "flex", gap: 6, marginBottom: 10, flexWrap: "wrap" }}>
        {filterButtons.map((f) => (
          <button
            key={f.id}
            className="btn"
            onClick={() => toggleFilter(f.id)}
            style={{
              padding: "6px 12px",
              fontSize: 12,
              background: activeFilters.has(f.id) ? "var(--accent)" : "transparent",
              color: activeFilters.has(f.id) ? "#fff" : "var(--text-dim)",
              border: "1px solid " + (activeFilters.has(f.id) ? "var(--accent)" : "var(--border)"),
            }}
          >
            {f.label}
          </button>
        ))}
      </div>
      <div style={{ display: "flex", gap: 6, marginBottom: 14, flexWrap: "wrap" }}>
        {depoOptions.map((d) => (
          <button
            key={d}
            className="btn"
            onClick={() => setDepoFilter(depoFilter === d ? null : d)}
            style={{
              padding: "5px 10px",
              fontSize: 11,
              background: depoFilter === d ? "var(--accent)" : "transparent",
              color: depoFilter === d ? "#fff" : "var(--text-dim)",
              border: "1px solid " + (depoFilter === d ? "var(--accent)" : "var(--border)"),
            }}
          >
            {d}
          </button>
        ))}
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {sorted.length === 0 && (
          <div className="panel" style={{ padding: 30, textAlign: "center", color: "var(--text-dim)" }}>
            {activeFilters.size === 0
              ? "Vyberte aspoň jeden filter."
              : "Žiadne záznamy v tomto filtri."}
          </div>
        )}
        {sorted.map((d) => (
          <ServiceEventCard key={d.id} d={d} technicianById={technicianById} user={user} onAssign={onAssign} onDelete={onDelete} onResolve={onResolve} onComplete={onComplete} onProtocol={onProtocol} locationLabel={locationLabel(d)} />
        ))}
      </div>
    </div>
  );
}

