/* ---------------------------------------------------------
   Technicians overview (today + tomorrow, per technician)
--------------------------------------------------------- */
function TechniciansOverview({ technicians, assignments, machines, damages, weeklyDuty, today, onOpenAssignment }) {
  const machineById = useMemo(() => Object.fromEntries(machines.map((m) => [m.id, m])), [machines]);
  const damageById = useMemo(() => Object.fromEntries((damages || []).map((d) => [d.id, d])), [damages]);
  const [technicianFilter, setTechnicianFilter] = useState("");
  const [depoFilter, setDepoFilter] = useState(null);
  const depoOptions = DEPO_OPTIONS;
  const QUICK_KIND_LABELS = { pohotovost: "Pohotovosť", dovolenka: "Dovolenka", pn: "PN / Doktor" };

  function isOnDuty(technicianId, iso) {
    return (weeklyDuty || []).some((w) => w.technicianId === technicianId && iso >= w.weekStart && iso <= w.weekEnd);
  }

  function daysForTechnician(t) {
    const list = [];
    let d = today;
    let guard = 0;
    while (list.length < 5 && guard < 60) {
      guard++;
      const dow = new Date(d + "T00:00:00").getDay();
      const isWeekend = dow === 0 || dow === 6;
      if (!isWeekend) {
        list.push(d);
      } else {
        const hasContent = assignments.some((a) => a.technicianId === t.id && a.date === d) || isOnDuty(t.id, d);
        if (hasContent) list.push(d);
      }
      d = addDaysISO(d, 1);
    }
    return list;
  }

  if (technicians.length === 0) {
    return (
      <div className="panel" style={{ padding: 30, textAlign: "center", color: "var(--text-dim)" }}>
        Zatiaľ nie sú pridaní žiadni technici. Pridajte ich v záložke „Technici“.
      </div>
    );
  }

  function jobLine(a) {
    const machine = a.machineId ? machineById[a.machineId] : null;
    const linkedDamage = a.damageId ? damageById[a.damageId] : null;
    const label = a.kind ? QUICK_KIND_LABELS[a.kind] || a.kind : (machine?.code || a.stroj || "— stroj neurčený —");
    const clickable = !a.kind;
    return (
      <div
        key={a.id}
        onClick={clickable ? () => onOpenAssignment(a, machine, linkedDamage) : undefined}
        style={{
          fontSize: 12,
          marginBottom: 4,
          paddingLeft: 8,
          borderLeft: `2px solid ${a.kind ? "var(--warn)" : linkedDamage ? damageColor(linkedDamage) : "var(--border)"}`,
          cursor: clickable ? "pointer" : "default",
        }}
      >
        <span style={{ fontWeight: 600, color: clickable ? "var(--accent)" : "inherit" }}>{label}</span>
        {!a.kind && (
          <span style={{ color: "var(--text-dim)" }}>{a.umiestnenie ? " · " + a.umiestnenie : ""}{a.firma ? " · " + a.firma : ""}</span>
        )}
        {a.poznamka && !a.kind && <div style={{ color: "var(--text-dim)" }}>{a.poznamka}</div>}
      </div>
    );
  }

  let visibleTechnicians = technicians.filter((t) => !t.archived);
  if (technicianFilter) visibleTechnicians = visibleTechnicians.filter((t) => t.id === technicianFilter);
  if (depoFilter) visibleTechnicians = visibleTechnicians.filter((t) => (t.depo || "").toLowerCase() === depoFilter.toLowerCase());

  return (
    <div>
      <div style={{ display: "flex", gap: 10, marginBottom: 10, flexWrap: "wrap", alignItems: "center" }}>
        <select value={technicianFilter} onChange={(e) => setTechnicianFilter(e.target.value)} style={{ minWidth: 220 }}>
          <option value="">— všetci technici —</option>
          {technicians.filter((t) => !t.archived).map((t) => (
            <option key={t.id} value={t.id}>{t.skratka ? `${t.skratka} — ${t.name}` : t.name}</option>
          ))}
        </select>
      </div>
      <div style={{ display: "flex", gap: 6, marginBottom: 14, flexWrap: "wrap" }}>
        {depoOptions.map((d) => (
          <button
            key={d}
            className="btn"
            onClick={() => setDepoFilter(depoFilter === d ? null : d)}
            style={{
              padding: "5px 10px",
              fontSize: 11,
              background: depoFilter === d ? "var(--accent)" : "transparent",
              color: depoFilter === d ? "#fff" : "var(--text-dim)",
              border: "1px solid " + (depoFilter === d ? "var(--accent)" : "var(--border)"),
            }}
          >
            {d}
          </button>
        ))}
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {visibleTechnicians.length === 0 && (
          <div className="panel" style={{ padding: 30, textAlign: "center", color: "var(--text-dim)" }}>
            Žiadny technik nezodpovedá filtru.
          </div>
        )}
        {visibleTechnicians.map((t) => {
          const techDays = daysForTechnician(t);
          return (
          <div key={t.id} className="panel" style={{ overflow: "hidden" }}>
            <div style={{ background: "#1a1a1a", color: "#fff", padding: "8px 14px", display: "flex", alignItems: "center", gap: 10 }}>
              <span className="label-font" style={{ fontSize: 13, fontWeight: 700, letterSpacing: ".04em", textTransform: "uppercase" }}>
                {t.skratka ? `${t.skratka} · ${t.name}` : t.name}
              </span>
              {(t.depo || t.spz) && (
                <span style={{ marginLeft: "auto", fontSize: 11, color: "rgba(255,255,255,.7)" }}>
                  {[t.depo, t.spz].filter(Boolean).join(" · ")}
                </span>
              )}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: `repeat(${techDays.length}, 1fr)`, overflowX: "auto" }}>
              {techDays.map((iso, i) => {
                const dayAssignments = assignments.filter((a) => a.technicianId === t.id && a.date === iso);
                const onDuty = isOnDuty(t.id, iso);
                const dow = new Date(iso + "T00:00:00").getDay();
                return (
                  <div key={iso} style={{ padding: 12, borderRight: i < techDays.length - 1 ? "1px solid var(--border)" : "none", minWidth: 130 }}>
                    <div style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".06em", color: "var(--text-dim)", marginBottom: 6 }}>
                      {DOW_NAMES_FULL[dow]} — {fmtDate(iso)}
                    </div>
                    {dayAssignments.length === 0 ? (
                      <div style={{ fontSize: 12, color: "var(--text-dim)" }}>Bez zákazky</div>
                    ) : (
                      dayAssignments.map(jobLine)
                    )}
                    {onDuty && (
                      <div style={{ fontSize: 11, color: "#6b7280", marginTop: 6, display: "flex", alignItems: "center", gap: 4 }}>
                        <span>☎</span> Služba na telefóne
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
          );
        })}
      </div>
    </div>
  );
}

/* ---------------------------------------------------------
   Technician card modal (karta technika)
--------------------------------------------------------- */
function TechnicianCardModal({ technician, assignments, machines, today, user, onClose, onEdit, onArchive, onUnarchive, onDelete }) {
  const t = technician;
  const machineById = useMemo(() => Object.fromEntries(machines.map((m) => [m.id, m])), [machines]);
  const upcoming = assignments
    .filter((a) => a.technicianId === t.id && a.date >= today)
    .sort((a, b) => (a.date < b.date ? -1 : 1))
    .slice(0, 8);

  return (
    <Modal title={`${t.name}${t.archived ? " (archivovaný)" : ""}`} onClose={onClose} wide>
      <div className="resp-grid" style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", border: "1px solid var(--border)", borderRadius: 8, overflow: "hidden", marginBottom: 14 }}>
        <CardField label="Skratka (ERP)" value={t.skratka} />
        <CardField label="ŠPZ servisného auta" value={t.spz} />
        <CardField label="Depo" value={t.depo} />
        <CardField label="Telefón" value={t.phone} />
        <CardField label="Email" value={t.email} />
      </div>
      <div style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".06em", color: "var(--text-dim)", marginBottom: 6 }}>
        Nadchádzajúce zákazky
      </div>
      {upcoming.length === 0 ? (
        <div style={{ fontSize: 13, color: "var(--text-dim)", marginBottom: 14 }}>Zatiaľ nič naplánované.</div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 14 }}>
          {upcoming.map((a) => {
            const machine = a.machineId ? machineById[a.machineId] : null;
            return (
              <div key={a.id} style={{ fontSize: 12, paddingLeft: 8, borderLeft: "2px solid var(--border)" }}>
                <span className="mono" style={{ fontWeight: 600 }}>{fmtDate(a.date)}</span>
                {" · "}
                <span style={{ fontWeight: 600 }}>{machine?.code || a.stroj || "— stroj neurčený —"}</span>
                <span style={{ color: "var(--text-dim)" }}>{a.umiestnenie ? " · " + a.umiestnenie : ""}{a.firma ? " · " + a.firma : ""}</span>
              </div>
            );
          })}
        </div>
      )}
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
        {can(user, "technician_edit") && <button className="btn btn-ghost" onClick={onEdit}>Upraviť</button>}
        {can(user, "technician_archive") && (
          <button className="btn btn-ghost" onClick={() => (t.archived ? onUnarchive() : onArchive())}>
            {t.archived ? "Vrátiť z archívu" : "Archivovať"}
          </button>
        )}
        {can(user, "technician_delete") && (
          <button className="btn btn-ghost" style={{ color: "var(--danger)" }} onClick={() => onDelete(t.id)}>
            Zmazať technika
          </button>
        )}
      </div>
    </Modal>
  );
}

/* ---------------------------------------------------------
   Technician service planner (Gantt, click day → assign)
--------------------------------------------------------- */
function TechnicianPlanner({ technicians, assignments, machines, damages, weeklyDuty, today, user, onCellClick, onQuickAssign, onQuickWeeklyDuty, onAddTechnician, onOpenTechnician }) {
  const [monthOffset, setMonthOffset] = useState(0);
  const [showArchived, setShowArchived] = useState(false);
  const [depoFilter, setDepoFilter] = useState(null);
  const [technicianFilter, setTechnicianFilter] = useState("");
  const [quickMode, setQuickMode] = useState(null); // null | 'pohotovost' | 'dovolenka' | 'pn' | 'sluzba'
  const QUICK_KINDS = [
    { id: "pohotovost", label: "Pohotovosť", color: "var(--danger)" },
    { id: "dovolenka", label: "Dovolenka", color: "var(--ok)" },
    { id: "pn", label: "PN / Doktor", color: "var(--warn)" },
    { id: "sluzba", label: "Služba na telefóne", color: "#6b7280", weekly: true },
  ];
  const DOW_NAMES = ["Ne", "Po", "Ut", "St", "Št", "Pi", "So"];
  function isOnDuty(technicianId, iso) {
    return (weeklyDuty || []).some((w) => w.technicianId === technicianId && iso >= w.weekStart && iso <= w.weekEnd);
  }
  const depoOptions = DEPO_OPTIONS;
  let visibleTechnicians = showArchived ? technicians : technicians.filter((t) => !t.archived);
  if (technicianFilter) {
    visibleTechnicians = visibleTechnicians.filter((t) => t.id === technicianFilter);
  }
  if (depoFilter) {
    visibleTechnicians = visibleTechnicians.filter((t) => (t.depo || "").toLowerCase() === depoFilter.toLowerCase());
  }
  const base = new Date(today + "T00:00:00");
  const viewDate = new Date(base.getFullYear(), base.getMonth() + monthOffset, 1);
  const year = viewDate.getFullYear();
  const month = viewDate.getMonth();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const monthLabel = viewDate.toLocaleDateString("sk-SK", { month: "long", year: "numeric" });

  const machineById = useMemo(() => Object.fromEntries(machines.map((m) => [m.id, m])), [machines]);
  const damageById = useMemo(() => Object.fromEntries((damages || []).map((d) => [d.id, d])), [damages]);
  const byTechDate = useMemo(() => {
    const map = {};
    assignments.forEach((a) => {
      const key = `${a.technicianId}_${a.date}`;
      (map[key] = map[key] || []).push(a);
    });
    return map;
  }, [assignments]);

  const monthStartISO = `${year}-${String(month + 1).padStart(2, "0")}-01`;
  const monthEndISO = `${year}-${String(month + 1).padStart(2, "0")}-${String(daysInMonth).padStart(2, "0")}`;

  function compressDates(dates) {
    const sorted = [...dates].sort();
    if (sorted.length === 0) return "";
    const ranges = [];
    let start = sorted[0], prev = sorted[0];
    for (let i = 1; i < sorted.length; i++) {
      const d = sorted[i];
      if (d === addDaysISO(prev, 1)) { prev = d; continue; }
      ranges.push(start === prev ? fmtDate(start) : `${fmtDate(start)}–${fmtDate(prev)}`);
      start = d; prev = d;
    }
    ranges.push(start === prev ? fmtDate(start) : `${fmtDate(start)}–${fmtDate(prev)}`);
    return ranges.join(", ");
  }

  const monthlySummary = useMemo(() => {
    return visibleTechnicians
      .map((t) => {
        const kindDates = { pohotovost: [], dovolenka: [], pn: [] };
        assignments.forEach((a) => {
          if (a.technicianId !== t.id || !a.kind || !(a.kind in kindDates)) return;
          if (a.date < monthStartISO || a.date > monthEndISO) return;
          kindDates[a.kind].push(a.date);
        });
        const dutyWeeks = (weeklyDuty || [])
          .filter((w) => w.technicianId === t.id && w.weekStart <= monthEndISO && w.weekEnd >= monthStartISO)
          .sort((a, b) => (a.weekStart < b.weekStart ? -1 : 1));
        return { technician: t, kindDates, dutyWeeks };
      })
      .filter((s) => s.dutyWeeks.length > 0 || Object.values(s.kindDates).some((arr) => arr.length > 0));
  }, [visibleTechnicians, assignments, weeklyDuty, monthStartISO, monthEndISO]);

  const todayCellRef = useRef(null);
  const scrollContainerRef = useRef(null);
  function scrollToToday() {
    try {
      const container = scrollContainerRef.current;
      const cell = todayCellRef.current;
      if (!container || !cell) return;
      const containerRect = container.getBoundingClientRect();
      const cellRect = cell.getBoundingClientRect();
      const delta = (cellRect.left + cellRect.width / 2) - (containerRect.left + containerRect.width / 2);
      container.scrollLeft = container.scrollLeft + delta;
    } catch (e) {
      // ignore — purely a convenience scroll
    }
  }

  useEffect(() => {
    if (monthOffset !== 0) return;
    const t = setTimeout(scrollToToday, 50);
    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [monthOffset]);

  if (technicians.length === 0) {
    return (
      <div className="panel" style={{ padding: 30, textAlign: "center", color: "var(--text-dim)" }}>
        Zatiaľ nie sú pridaní žiadni technici.
        <div style={{ marginTop: 12 }}>
          {can(user, "technician_add") && <button className="btn btn-accent" onClick={onAddTechnician}>+ Pridať technika</button>}
        </div>
      </div>
    );
  }

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 14, flexWrap: "wrap" }}>
        <button className="btn btn-ghost" style={{ padding: "5px 10px" }} onClick={() => setMonthOffset((o) => o - 1)}>←</button>
        <span className="label-font" style={{ fontSize: 15, minWidth: 160, textAlign: "center", textTransform: "capitalize" }}>{monthLabel}</span>
        <button className="btn btn-ghost" style={{ padding: "5px 10px" }} onClick={() => setMonthOffset((o) => o + 1)}>→</button>
        {monthOffset !== 0 && (
          <button className="btn btn-ghost" style={{ padding: "5px 10px", fontSize: 11 }} onClick={() => setMonthOffset(0)}>Dnes</button>
        )}
        <button
          className="btn btn-ghost"
          style={{ padding: "5px 10px", fontSize: 11 }}
          onClick={() => {
            if (monthOffset !== 0) {
              setMonthOffset(0);
              setTimeout(scrollToToday, 60);
            } else {
              scrollToToday();
            }
          }}
        >
          → Choď na dnešný deň
        </button>
        <label style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: "var(--text-dim)", marginLeft: 8 }}>
          <input type="checkbox" checked={showArchived} onChange={(e) => setShowArchived(e.target.checked)} />
          Zobraziť archivovaných
        </label>
        <select value={technicianFilter} onChange={(e) => setTechnicianFilter(e.target.value)} style={{ minWidth: 200 }}>
          <option value="">— všetci technici —</option>
          {technicians.filter((t) => !t.archived).map((t) => (
            <option key={t.id} value={t.id}>{t.skratka ? `${t.skratka} — ${t.name}` : t.name}</option>
          ))}
        </select>
        <div style={{ flex: 1 }} />
        {can(user, "technician_add") && <button className="btn btn-accent" onClick={onAddTechnician}>+ Pridať technika</button>}
      </div>
      {monthlySummary.length > 0 && (
        <div className="panel" style={{ padding: 14, marginBottom: 14 }}>
          <div style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".06em", color: "var(--text-dim)", marginBottom: 8 }}>
            Rýchly prehľad — {monthLabel}
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {monthlySummary.map((s) => (
              <div key={s.technician.id} style={{ fontSize: 13, display: "flex", flexWrap: "wrap", gap: 4 }}>
                <span style={{ fontWeight: 600 }}>{s.technician.name}:</span>
                {s.kindDates.pohotovost.length > 0 && (
                  <span><span style={{ color: "var(--danger)", fontWeight: 600 }}>Pohotovosť</span> {compressDates(s.kindDates.pohotovost)}</span>
                )}
                {s.kindDates.dovolenka.length > 0 && (
                  <span>{s.kindDates.pohotovost.length > 0 ? " · " : ""}<span style={{ color: "var(--ok)", fontWeight: 600 }}>Dovolenka</span> {compressDates(s.kindDates.dovolenka)}</span>
                )}
                {s.kindDates.pn.length > 0 && (
                  <span>{(s.kindDates.pohotovost.length > 0 || s.kindDates.dovolenka.length > 0) ? " · " : ""}<span style={{ color: "var(--warn)", fontWeight: 600 }}>PN / Doktor</span> {compressDates(s.kindDates.pn)}</span>
                )}
                {s.dutyWeeks.map((w) => (
                  <span key={w.id}>
                    {(s.kindDates.pohotovost.length > 0 || s.kindDates.dovolenka.length > 0 || s.kindDates.pn.length > 0) ? " · " : ""}
                    <span style={{ color: "#6b7280", fontWeight: 600 }}>☎ Služba</span> {fmtDate(w.weekStart)}–{fmtDate(w.weekEnd)}
                  </span>
                ))}
              </div>
            ))}
          </div>
        </div>
      )}
      <div style={{ display: "flex", gap: 6, marginBottom: 14, flexWrap: "wrap" }}>
        {depoOptions.map((d) => (
          <button
            key={d}
            className="btn"
            onClick={() => setDepoFilter(depoFilter === d ? null : d)}
            style={{
              padding: "5px 10px",
              fontSize: 11,
              background: depoFilter === d ? "var(--accent)" : "transparent",
              color: depoFilter === d ? "#fff" : "var(--text-dim)",
              border: "1px solid " + (depoFilter === d ? "var(--accent)" : "var(--border)"),
            }}
          >
            {d}
          </button>
        ))}
      </div>
      {can(user, "plan_quick_events") && (
        <div style={{ display: "flex", gap: 6, marginBottom: 14, flexWrap: "wrap", alignItems: "center" }}>
          <span style={{ fontSize: 11, color: "var(--text-dim)" }}>Rýchle udalosti:</span>
          {QUICK_KINDS.map((k) => (
            <button
              key={k.id}
              className="btn"
              onClick={() => setQuickMode(quickMode === k.id ? null : k.id)}
              style={{
                padding: "5px 10px",
                fontSize: 11,
                background: quickMode === k.id ? k.color : "transparent",
                color: quickMode === k.id ? "#fff" : k.color,
                border: "1px solid " + k.color,
              }}
            >
              {k.label}
            </button>
          ))}
          {quickMode && (
            <span style={{ fontSize: 11, color: "var(--text-dim)" }}>
              — kliknite na bunky technikov, kam chcete "{QUICK_KINDS.find((k) => k.id === quickMode)?.label}" pridať
            </span>
          )}
        </div>
      )}
      <div className="panel" style={{ padding: 16 }}>
        <div ref={scrollContainerRef} style={{ overflow: "auto", maxHeight: "65vh" }}>
          <div style={{ minWidth: "max-content" }}>
            <div
              style={{
                display: "grid",
                gridTemplateColumns: `var(--gantt-name-col) repeat(${daysInMonth}, var(--gantt-plan-day-col))`,
                gap: 2,
                position: "sticky",
                top: 0,
                zIndex: 4,
                background: "var(--panel)",
              }}
            >
              <div style={{ position: "sticky", left: 0, zIndex: 5, background: "var(--panel)" }}></div>
              {Array.from({ length: daysInMonth }, (_, i) => i + 1).map((d) => {
                const iso = `${year}-${String(month + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
                const isToday = iso === today;
                const dow = new Date(year, month, d).getDay();
                const isWeekend = dow === 0 || dow === 6;
                return (
                  <div
                    key={d}
                    ref={isToday ? todayCellRef : null}
                    className="mono gantt-header-cell"
                    title={iso}
                    style={{
                      textAlign: "center",
                      fontSize: 11,
                      color: isToday ? "var(--accent)" : isWeekend ? "var(--warn)" : "var(--text-dim)",
                      fontWeight: isToday ? 700 : 400,
                      whiteSpace: "nowrap",
                      borderRight: "1px solid var(--border)",
                      paddingBottom: 4,
                      background: isWeekend ? "var(--warn-bg)" : "var(--panel)",
                    }}
                  >
                    <div style={{ fontSize: 9, textTransform: "uppercase", letterSpacing: ".03em" }}>{DOW_NAMES[dow]}</div>
                    <div>{d}</div>
                  </div>
                );
              })}
            </div>

            {visibleTechnicians.map((t) => (
              <div
                key={t.id}
                style={{
                  display: "grid",
                  gridTemplateColumns: `var(--gantt-name-col) repeat(${daysInMonth}, var(--gantt-plan-day-col))`,
                  gap: 2,
                  marginBottom: 3,
                }}
              >
                <div
                  onClick={() => onOpenTechnician(t)}
                  style={{
                    lineHeight: 1.3,
                    whiteSpace: "nowrap",
                    overflow: "hidden",
                    textOverflow: "ellipsis",
                    cursor: "pointer",
                    position: "sticky",
                    left: 0,
                    zIndex: 2,
                    background: "var(--panel)",
                    paddingRight: 6,
                    paddingTop: 4,
                  }}
                  title="Zobraziť kartu technika"
                >
                  <div style={{ fontSize: 12, fontWeight: 600, color: "var(--accent)", overflow: "hidden", textOverflow: "ellipsis" }}>
                    {t.name}
                  </div>
                  {t.depo && (
                    <div style={{ fontSize: 10, color: "var(--text-dim)", overflow: "hidden", textOverflow: "ellipsis" }}>
                      {t.depo}
                    </div>
                  )}
                </div>
                {Array.from({ length: daysInMonth }, (_, i) => i + 1).map((d) => {
                  const iso = `${year}-${String(month + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
                  const dow = new Date(year, month, d).getDay();
                  const isWeekend = dow === 0 || dow === 6;
                  const dayAssignments = byTechDate[`${t.id}_${iso}`] || [];
                  const dutyRecord = (weeklyDuty || []).find((w) => w.technicianId === t.id && iso >= w.weekStart && iso <= w.weekEnd);
                  const onDuty = !!dutyRecord;
                  const isDutyStart = onDuty && iso === dutyRecord.weekStart;
                  const handleClick = () =>
                    quickMode === "sluzba"
                      ? onQuickWeeklyDuty(t.id, iso)
                      : quickMode
                      ? onQuickAssign(t.id, iso, quickMode)
                      : onCellClick(t.id, iso);
                  const clickTitle =
                    quickMode === "sluzba"
                      ? "Nastaviť/zrušiť službu na telefóne pre celý týždeň"
                      : quickMode
                      ? `Pridať "${QUICK_KINDS.find((k) => k.id === quickMode)?.label}"`
                      : "Kliknite pre pridelenie";
                  return (
                    <div key={d} style={{ display: "flex", flexDirection: "column", gap: 2 }}>
                      {dayAssignments.length === 0 ? (
                        <div
                          onClick={handleClick}
                          title={clickTitle}
                          style={{
                            height: 26,
                            borderRadius: 4,
                            background: isWeekend ? "var(--warn-bg)" : "var(--panel-2)",
                            border: "1px dashed var(--border)",
                            cursor: "pointer",
                          }}
                        />
                      ) : (
                        dayAssignments.map((a) => {
                          const machine = a.machineId ? machineById[a.machineId] : null;
                          const linkedDamage = a.damageId ? damageById[a.damageId] : null;
                          const quickKind = a.kind ? QUICK_KINDS.find((k) => k.id === a.kind) : null;
                          const bg = quickKind ? quickKind.color : linkedDamage ? damageColor(linkedDamage) : "var(--info)";
                          const label = quickKind ? quickKind.label : (machine?.code || a.stroj || a.firma || "•");
                          const tooltip = quickKind
                            ? quickKind.label
                            : `${machine?.code || a.stroj || "—"} · ${a.umiestnenie || "—"} · ${a.firma || "—"}${linkedDamage ? " · " + damageLabel(linkedDamage) : ""}`;
                          return (
                            <div
                              key={a.id}
                              onClick={handleClick}
                              title={tooltip}
                              style={{
                                height: 22,
                                borderRadius: 4,
                                background: bg,
                                color: "#fff",
                                fontSize: 9,
                                fontWeight: 600,
                                display: "flex",
                                alignItems: "center",
                                justifyContent: "center",
                                whiteSpace: "nowrap",
                                overflow: "hidden",
                                textOverflow: "ellipsis",
                                cursor: "pointer",
                                padding: "0 4px",
                              }}
                              className="gantt-cell"
                            >
                              {label}
                            </div>
                          );
                        })
                      )}
                      {onDuty && (
                        <div
                          onClick={handleClick}
                          title="Služba na telefóne (celý týždeň)"
                          style={{
                            height: 11,
                            borderRadius: 3,
                            background: "#6b7280",
                            opacity: 0.85,
                            cursor: "pointer",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: isDutyStart ? "flex-start" : "center",
                            paddingLeft: isDutyStart ? 3 : 0,
                            fontSize: 8,
                            lineHeight: 1,
                            color: "#fff",
                          }}
                        >
                          {isDutyStart ? "☎" : ""}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function AssignSlotModal({ slot, assignments, machines, damages, machineById, technicians, user, onClose, onSave, onDelete }) {
  const technician = technicians.find((t) => t.id === slot.technicianId);
  const dayAssignments = assignments.filter((a) => a.technicianId === slot.technicianId && a.date === slot.date);
  const [editingId, setEditingId] = useState(dayAssignments.length ? null : "new");

  function protocolParamsFor(a, machine) {
    const linkedDamage = a.damageId ? (damages || []).find((d) => d.id === a.damageId) : null;
    if (linkedDamage) {
      // Rieši aj externé zákazky (zaškrtne "Externý stroj", ťahá sériové číslo/model z hlásenia namiesto z databázy strojov)
      return buildProtocolParams(linkedDamage, technicians, machineById || {});
    }
    const params = {};
    const serial = machine?.code || a.stroj || "";
    if (serial) params.serial = serial;
    if (technician?.name) params.tech = technician.name;
    if (a.umiestnenie) params.address = a.umiestnenie;
    return params;
  }

  return (
    <Modal title={`${technician?.name || "Technik"} · ${fmtDate(slot.date)}`} onClose={onClose} wide>
      {dayAssignments.length > 0 && (
        <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 14 }}>
          {dayAssignments.map((a) => {
            const machine = a.machineId ? machines.find((m) => m.id === a.machineId) : null;
            if (editingId === a.id) return null;
            return (
              <div key={a.id} className="panel" style={{ padding: 12, display: "flex", justifyContent: "space-between", gap: 10, alignItems: "flex-start" }}>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13 }}>
                    {machine?.code || a.stroj || "— stroj neurčený —"}{machine?.type ? ` · ${machine.type}` : ""}
                  </div>
                  <div style={{ fontSize: 12, color: "var(--text-dim)" }}>{a.umiestnenie || "—"}{a.firma ? " · " + a.firma : ""}</div>
                  {a.poznamka && <div style={{ fontSize: 12, marginTop: 4 }}>{a.poznamka}</div>}
                </div>
                <div style={{ display: "flex", gap: 6, flexShrink: 0, flexWrap: "wrap" }}>
                  {can(user, "plan_assign") && <button className="btn btn-ghost" style={{ fontSize: 11, padding: "4px 8px" }} onClick={() => setEditingId(a.id)}>Upraviť</button>}
                  {can(user, "protocol_write") && <button className="btn btn-ghost" style={{ fontSize: 11, padding: "4px 8px" }} onClick={() => openProtocol(protocolParamsFor(a, machine))}>Protokol</button>}
                  {can(user, "plan_assign") && <button className="btn btn-ghost" style={{ fontSize: 11, padding: "4px 8px", color: "var(--danger)" }} onClick={() => onDelete(a.id)}>Zmazať</button>}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {editingId === null && can(user, "plan_assign") && (
        <button className="btn btn-accent" onClick={() => setEditingId("new")}>+ Pridať ďalšiu zákazku</button>
      )}

      {editingId !== null && (
        <div style={{ borderTop: dayAssignments.length > 0 ? "1px solid var(--border)" : "none", paddingTop: dayAssignments.length > 0 ? 14 : 0 }}>
          <AssignJobForm
            key={editingId}
            existing={editingId === "new" ? null : dayAssignments.find((a) => a.id === editingId)}
            machines={machines}
            onCancel={() => setEditingId(null)}
            onSave={(data) => {
              onSave(data, editingId === "new" ? null : editingId);
              setEditingId(null);
            }}
          />
        </div>
      )}
    </Modal>
  );
}

function AssignJobForm({ existing, machines, onCancel, onSave }) {
  const [machineId, setMachineId] = useState(existing?.machineId || "");
  const [stroj, setStroj] = useState(existing?.stroj || "");
  const [umiestnenie, setUmiestnenie] = useState(existing?.umiestnenie || "");
  const [firma, setFirma] = useState(existing?.firma || "");
  const [poznamka, setPoznamka] = useState(existing?.poznamka || "");

  const machineOptions = machines.map((m) => ({ value: m.id, label: `${m.code}${m.type ? " — " + m.type : ""}` }));
  const canSave = machineId || stroj.trim();

  return (
    <div>
      <Field label="Stroj (vybrať zo zoznamu)">
        <SearchSelect options={machineOptions} value={machineId} onChange={(v) => { setMachineId(v); setStroj(""); }} placeholder="Vybrať stroj…" />
      </Field>
      <Field label="…alebo stroj mimo evidencie (voľný text)">
        <input value={stroj} onChange={(e) => { setStroj(e.target.value); setMachineId(""); }} placeholder="napr. externý stroj zákazníka" style={{ width: "100%" }} />
      </Field>
      <div className="resp-grid" style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
        <Field label="Umiestnenie"><input value={umiestnenie} onChange={(e) => setUmiestnenie(e.target.value)} style={{ width: "100%" }} /></Field>
        <Field label="Firma"><input value={firma} onChange={(e) => setFirma(e.target.value)} style={{ width: "100%" }} /></Field>
      </div>
      <Field label="Poznámka (čo tam je, aké diely vziať…)">
        <textarea value={poznamka} onChange={(e) => setPoznamka(e.target.value)} rows={3} style={{ width: "100%" }} />
      </Field>
      <div style={{ display: "flex", gap: 8 }}>
        <button
          className="btn btn-accent"
          disabled={!canSave}
          onClick={() =>
            onSave({
              machineId: machineId || null,
              stroj: machineId ? "" : stroj.trim(),
              umiestnenie: umiestnenie.trim(),
              firma: firma.trim(),
              poznamka: poznamka.trim(),
            })
          }
        >
          Uložiť
        </button>
        <button className="btn btn-ghost" onClick={onCancel}>Zrušiť</button>
      </div>
    </div>
  );
}

/* ---------------------------------------------------------
   Global style / design tokens
--------------------------------------------------------- */
/* ---------------------------------------------------------
   Login / registrácia — cez Supabase Auth
   (Prvý človek, čo sa kedy zaregistruje, sa automaticky stane
   administrátorom — vybaví to databázový trigger, nie appka.)
--------------------------------------------------------- */
function LoginScreen({ onLogin, onSignUp }) {
  const [mode, setMode] = useState("login"); // "login" | "signup"
  const [email, setEmail] = useState("");
  const [name, setName] = useState("");
  const [password, setPassword] = useState("");
  const [password2, setPassword2] = useState("");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");
  const [info, setInfo] = useState("");

  async function handleLogin() {
    setError(""); setInfo("");
    if (!email.trim() || !password) { setError("Zadajte email aj heslo."); return; }
    setBusy(true);
    const result = await onLogin(email.trim(), password);
    setBusy(false);
    if (!result.ok) setError(result.message);
  }

  async function handleSignUp() {
    setError(""); setInfo("");
    if (!email.trim() || !name.trim() || !password) { setError("Vyplňte všetky polia."); return; }
    if (password.length < 6) { setError("Heslo musí mať aspoň 6 znakov."); return; }
    if (password !== password2) { setError("Heslá sa nezhodujú."); return; }
    setBusy(true);
    const result = await onSignUp({ email: email.trim(), password, name: name.trim() });
    setBusy(false);
    if (!result.ok) { setError(result.message); return; }
    if (result.needsConfirmation) {
      setInfo("Účet bol vytvorený. Skontrolujte email a potvrďte ho kliknutím na odkaz, potom sa môžete prihlásiť.");
      setMode("login");
    }
  }

  return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: "100vh", background: "var(--bg)" }}>
      <div className="panel" style={{ padding: 32, width: 360, maxWidth: "90vw" }}>
        <div className="label-font" style={{ fontSize: 22, fontWeight: 700, color: "var(--accent)", marginBottom: 4, textTransform: "lowercase" }}>mateco</div>
        <div style={{ fontSize: 14, color: "var(--text-dim)", marginBottom: 20 }}>
          {mode === "login" ? "Interná platforma — prihlásenie" : "Vytvorenie nového účtu"}
        </div>

        <Field label="Email">
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && mode === "login" && handleLogin()}
            style={{ width: "100%" }}
            autoFocus
          />
        </Field>
        {mode === "signup" && (
          <Field label="Celé meno">
            <input value={name} onChange={(e) => setName(e.target.value)} style={{ width: "100%" }} />
          </Field>
        )}
        <Field label="Heslo">
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && mode === "login" && handleLogin()}
            style={{ width: "100%" }}
          />
        </Field>
        {mode === "signup" && (
          <Field label="Zopakovať heslo">
            <input type="password" value={password2} onChange={(e) => setPassword2(e.target.value)} style={{ width: "100%" }} />
          </Field>
        )}

        {error && <div style={{ color: "var(--danger)", fontSize: 13, marginBottom: 12 }}>{error}</div>}
        {info && <div style={{ color: "var(--ok)", fontSize: 13, marginBottom: 12 }}>{info}</div>}

        <button className="btn btn-accent" style={{ width: "100%", marginBottom: 10 }} disabled={busy} onClick={mode === "login" ? handleLogin : handleSignUp}>
          {busy ? "Chvíľu strpenia…" : mode === "login" ? "Prihlásiť sa" : "Vytvoriť účet"}
        </button>
        <button
          className="btn btn-ghost"
          style={{ width: "100%" }}
          onClick={() => { setMode(mode === "login" ? "signup" : "login"); setError(""); setInfo(""); }}
        >
          {mode === "login" ? "Nemám ešte účet — zaregistrovať sa" : "Mám už účet — prihlásiť sa"}
        </button>
        {mode === "signup" && (
          <div style={{ fontSize: 12, color: "var(--text-dim)", marginTop: 12 }}>
            Po zaregistrovaní vám administrátor pridelí rolu (čo môžete v appke robiť). Kým sa tak nestane, uvidíte appku len na čítanie.
          </div>
        )}
      </div>
    </div>
  );
}

/* ---------------------------------------------------------
   User admin console (admin only) — spravuje profily (rola,
   meno, aktívny/neaktívny). Heslá a samotné vytváranie účtov
   rieši Supabase Auth priamo (kolegovia sa registrujú sami).
--------------------------------------------------------- */
function UserAdminModal({ profiles, currentUser, onClose, onUpdate, onDelete }) {
  const [editingId, setEditingId] = useState(null);

  return (
    <Modal title="Správa používateľov" onClose={onClose} wide>
      <div style={{ fontSize: 13, color: "var(--text-dim)", marginBottom: 14 }}>
        Noví ľudia sa registrujú sami na prihlasovacej obrazovke — tu im len prideľte rolu, prípadne ich deaktivujte/zmažte.
      </div>
      <table>
        <thead>
          <tr>
            <th>Meno</th>
            <th>Email</th>
            <th>Rola</th>
            <th>Stav</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          {profiles.length === 0 && (
            <tr><td colSpan={5} style={{ textAlign: "center", padding: 30, color: "var(--text-dim)" }}>Zatiaľ žiadni používatelia.</td></tr>
          )}
          {profiles.map((p) => (
            <tr key={p.id}>
              <td style={{ fontWeight: 600 }}>{p.name}{p.id === currentUser?.id ? " (vy)" : ""}</td>
              <td className="mono">{p.id === currentUser?.id ? currentUser.email : "—"}</td>
              <td>
                {editingId === p.id ? (
                  <select
                    autoFocus
                    defaultValue={p.role}
                    onChange={(e) => { onUpdate(p.id, { role: e.target.value }); setEditingId(null); }}
                    onBlur={() => setEditingId(null)}
                  >
                    {ROLES.map((r) => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                ) : (
                  <span style={{ cursor: "pointer", textDecoration: "underline" }} onClick={() => setEditingId(p.id)}>
                    {roleLabel(p.role)}
                  </span>
                )}
              </td>
              <td>{p.active === false ? <span className="badge badge-danger">Deaktivovaný</span> : <span className="badge badge-ok">Aktívny</span>}</td>
              <td style={{ display: "flex", gap: 6, justifyContent: "flex-end", flexWrap: "wrap" }}>
                <button
                  className="btn btn-ghost"
                  style={{ fontSize: 11, padding: "4px 8px" }}
                  onClick={() => onUpdate(p.id, { active: p.active === false ? true : false })}
                >
                  {p.active === false ? "Aktivovať" : "Deaktivovať"}
                </button>
                {p.id !== currentUser?.id && (
                  <button className="btn btn-ghost" style={{ fontSize: 11, padding: "4px 8px", color: "var(--danger)" }} onClick={() => onDelete(p.id)}>
                    Zmazať
                  </button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </Modal>
  );
}

