/* ---------------------------------------------------------
   Error boundary — ak niečo v appke zlyhá pri vykresľovaní,
   zachytí to appka sama (namiesto toho, aby to "vypadlo" von).
--------------------------------------------------------- */
class AppErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  componentDidCatch(error, info) {
    console.error("mateco-app crashed:", error, info);
  }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: 40, fontFamily: "Barlow, sans-serif", maxWidth: 640, margin: "40px auto" }}>
          <h2 style={{ color: "#E30613", marginBottom: 12 }}>Nastala neočakávaná chyba</h2>
          <p style={{ marginBottom: 16, color: "#333" }}>
            Appka narazila na chybu pri vykresľovaní tejto obrazovky. Skúste to znova — ak sa to opakuje, dajte mi vedieť presne, čo ste práve robili.
          </p>
          <button
            onClick={() => this.setState({ hasError: false, error: null })}
            style={{
              padding: "9px 18px",
              background: "#E30613",
              color: "#fff",
              border: "none",
              borderRadius: 6,
              fontFamily: "Barlow, sans-serif",
              fontWeight: 600,
              cursor: "pointer",
              marginBottom: 16,
            }}
          >
            Skúsiť znova
          </button>
          <details style={{ whiteSpace: "pre-wrap", fontSize: 12, color: "#777" }}>
            <summary style={{ cursor: "pointer" }}>Technický detail</summary>
            {String(this.state.error && this.state.error.stack ? this.state.error.stack : this.state.error)}
          </details>
        </div>
      );
    }
    return this.props.children;
  }
}

export default function App() {
  return (
    <AppErrorBoundary>
      <DispatcherApp />
    </AppErrorBoundary>
  );
}
